(function(){var stripe=null;var stripeInitPromise=null;var checkoutInstance=null;var checkoutFormTouched=false;var hasStartedPurchaseIntent=false;var hasSubmittedPurchaseIntent=false;var hasTrackedFormStart=false;var storeFlowId=null;var OFFER_DETAILS={cefc_enrollment:{label:'CEFC Enrollment Access',price:'$695',nextStep:'Best if you want the full graded pathway. EFI confirms your enrollment route within 1 business day, then you can begin module submissions on your timeline.',urgency:'To stay eligible for the July 30 capstone review window, enrollment requests should be in by July 23.'},capstone_review:{label:'Capstone Review & Credentialing',price:'$350',nextStep:'Best if your modules are already complete. EFI confirms capstone-readiness and review routing before your final packet enters the queue.',urgency:'Capstone-only buyers should secure review routing before July 23 to stay in the current July 30 window.'},cefc_bundle:{label:'CEFC Bundle',price:'$895',nextStep:'Best if you want the cleanest start-to-finish route. EFI confirms bundle checkout first, then keeps enrollment and capstone tracking under one account record.',urgency:'Bundle buyers who enter before July 23 are placed in the current review-cycle onboarding group.'},esqr_analysis:{label:'ESQ-R Professional Analysis',price:'$199',nextStep:'Best if you want a lower-commitment starting point. EFI follows up within 1 business day with scoring, interpretation, and the next recommended route.',urgency:'ESQ-R analysis does not depend on the capstone window, but selecting it now keeps your intake and later upgrade path on one record.'}};function getPageName(){return window.location.pathname.split('/').pop()||'store.html';}
function ensureStoreFlowId(){if(storeFlowId)return storeFlowId;try{var existing=window.sessionStorage.getItem('efi_store_flow_id');if(existing){storeFlowId=existing;return storeFlowId;}
storeFlowId='store_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,8);window.sessionStorage.setItem('efi_store_flow_id',storeFlowId);return storeFlowId;}catch(err){storeFlowId='store_'+Date.now().toString(36);return storeFlowId;}}
function trackStoreEvent(eventName,properties){var payload=Object.assign({funnel_flow_id:ensureStoreFlowId(),page:getPageName()},properties||{});if(window.EFI&&EFI.Analytics&&EFI.Analytics.track){EFI.Analytics.track(eventName,payload);}}
async function getStripe(){if(stripe)return stripe;if(stripeInitPromise)return stripeInitPromise;stripeInitPromise=(async function(){if(typeof window.Stripe==='undefined'){throw new Error('Stripe.js is unavailable on this page.');}
var response=await fetch('/api/public-config');var config=await response.json().catch(function(){return{};});if(!response.ok||!config.ok||!config.stripePublicKey){throw new Error('Stripe checkout is not configured.');}
stripe=Stripe(config.stripePublicKey);return stripe;})().catch(function(err){stripeInitPromise=null;throw err;});return stripeInitPromise;}
function showMessage(node,text,isError){if(!node)return;node.textContent=text;node.style.color=isError?'var(--color-danger, #b42318)':'var(--color-success, #067647)';}
function getFormPayload(form){var name=(form.querySelector('#purchase-name')||{}).value||'';var email=(form.querySelector('#purchase-email')||{}).value||'';var offer=(form.querySelector('#purchase-offer')||{}).value||'';return{name:String(name).trim(),email:String(email).trim(),offer:String(offer).trim()};}
function updateOfferState(form){if(!form)return;var payload=getFormPayload(form);var details=OFFER_DETAILS[payload.offer]||null;var summaryCard=document.getElementById('offer-summary-card');var summary=document.getElementById('offer-summary');var nextStep=document.getElementById('offer-next-step');var urgency=document.getElementById('offer-window-note');var submitBtn=document.getElementById('purchase-intent-submit');var checkoutBtn=document.getElementById('direct-checkout-btn');if(!details){if(summaryCard)summaryCard.hidden=true;if(summary)summary.textContent='';if(nextStep)nextStep.textContent='';if(urgency){urgency.textContent='Choose your offer to see the exact next-step timing and how this window affects your route.';}
if(submitBtn)submitBtn.textContent='Start Purchase Request';if(checkoutBtn)checkoutBtn.textContent='Go To Secure Checkout';return;}
if(summaryCard)summaryCard.hidden=false;if(summary){summary.textContent=details.label+' — '+details.price;}
if(nextStep){nextStep.textContent=details.nextStep;}
if(urgency){urgency.textContent=details.urgency;}
if(submitBtn){submitBtn.textContent='Request '+details.label;}
if(checkoutBtn){checkoutBtn.textContent='Open '+details.price+' Checkout';}}
async function submitPurchaseIntent(form){var consent=form.querySelector('#purchase-consent')&&form.querySelector('#purchase-consent').checked;var message=document.getElementById('purchase-intent-message');var btn=form.querySelector('button[type="submit"]');var payload=getFormPayload(form);if(!consent){showMessage(message,'Please confirm consent before submitting.',true);return;}
trackStoreEvent('store_lead_submit_started',{funnel_offer:payload.offer,email_present:!!payload.email});var original=btn.textContent;btn.disabled=true;btn.textContent='Submitting...';showMessage(message,'',false);try{var response=await fetch('/api/leads',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:payload.name,email:payload.email,consent:true,source:'store_purchase_intent',lead_type:'purchase_intent',metadata:{offer:payload.offer,page:window.location.pathname.split('/').pop()||'store.html'}})});var result=await response.json();if(!response.ok||!result.ok){throw new Error((result&&result.error)||'Unable to submit purchase request right now.');}
hasSubmittedPurchaseIntent=true;trackStoreEvent('store_purchase_intent_submitted',{funnel_offer:payload.offer,lead_id:result.lead_id||''});showMessage(message,'Request received. ExEF will follow up with onboarding steps within 1 business day.',false);}catch(err){trackStoreEvent('store_lead_submit_error',{funnel_offer:payload.offer,error:String(err&&err.message||err||'unknown_error')});showMessage(message,err.message||'Submission failed. Please try again.',true);}finally{btn.disabled=false;btn.textContent=original;}}
function openModal(summaryData){var modal=document.getElementById('checkout-modal');var titleEl=document.getElementById('checkout-modal-title');var priceEl=document.getElementById('checkout-modal-price');var includesList=document.getElementById('checkout-modal-includes');if(!modal)return;if(titleEl)titleEl.textContent=summaryData.offerLabel||'';if(priceEl)priceEl.textContent=summaryData.priceDisplay||'';if(includesList){includesList.innerHTML='';(summaryData.includes||[]).forEach(function(item){var li=document.createElement('li');li.textContent='✓ '+item;includesList.appendChild(li);});}
checkoutFormTouched=true;modal.style.display='';document.body.style.overflow='hidden';}
function closeModal(){var modal=document.getElementById('checkout-modal');if(checkoutFormTouched){if(!confirm('Leave checkout? Your payment has not been submitted.'))return;}
if(checkoutInstance){checkoutInstance.destroy();checkoutInstance=null;}
var container=document.getElementById('stripe-checkout-container');if(container)container.innerHTML='';checkoutFormTouched=false;if(modal)modal.style.display='none';document.body.style.overflow='';trackStoreEvent('store_checkout_modal_closed',{stage:'embedded_checkout'});}
async function startDirectCheckout(form){var message=document.getElementById('purchase-intent-message');var checkoutBtn=document.getElementById('direct-checkout-btn');var payload=getFormPayload(form);if(!payload.offer){showMessage(message,'Select an offer before launching checkout.',true);return;}
if(!payload.email||payload.email.indexOf('@')===-1){showMessage(message,'Enter a valid email to prefill checkout.',true);return;}
if(!checkoutBtn)return;trackStoreEvent('store_checkout_launch_clicked',{funnel_offer:payload.offer,email_present:!!payload.email});var original=checkoutBtn.textContent;checkoutBtn.disabled=true;checkoutBtn.textContent='Opening checkout…';showMessage(message,'',false);try{var response=await fetch('/api/create-checkout-session',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({offer:payload.offer,email:payload.email,name:payload.name})});var result=await response.json();if(!response.ok||!result.ok||!result.clientSecret){throw new Error((result&&result.error)||'Could not open checkout.');}
trackStoreEvent('store_checkout_session_created',{funnel_offer:payload.offer,destination:'stripe_embedded'});var stripeClient=await getStripe();trackStoreEvent('store_embedded_checkout_opened',{funnel_offer:payload.offer,destination:'stripe_embedded'});openModal(result);checkoutInstance=await stripeClient.initEmbeddedCheckout({clientSecret:result.clientSecret});var container=document.getElementById('stripe-checkout-container');if(!container)throw new Error('Checkout container not found.');checkoutInstance.mount(container);trackStoreEvent('store_checkout_mount_succeeded',{funnel_offer:payload.offer,destination:'stripe_embedded'});}catch(err){trackStoreEvent('store_checkout_launch_error',{funnel_offer:payload.offer,error:String(err&&err.message||err||'unknown_error')});showMessage(message,err.message||'Could not open checkout.',true);}finally{checkoutBtn.disabled=false;checkoutBtn.textContent=original;}}
function initAbandonTracking(form){['input','change'].forEach(function(evt){form.addEventListener(evt,function(event){hasStartedPurchaseIntent=true;if(!hasTrackedFormStart){hasTrackedFormStart=true;trackStoreEvent('store_checkout_form_started',{funnel_offer:getFormPayload(form).offer,interaction_type:evt});}
if(event&&event.target&&event.target.id==='purchase-offer'){trackStoreEvent('store_checkout_offer_selected',{funnel_offer:String(event.target.value||'').trim()});}});});window.addEventListener('beforeunload',function(){if(checkoutFormTouched){trackStoreEvent('store_checkout_abandoned',{funnel_offer:getFormPayload(form).offer,stage:'embedded_checkout'});return;}
if(!hasStartedPurchaseIntent||hasSubmittedPurchaseIntent)return;trackStoreEvent('store_purchase_intent_abandoned',{funnel_offer:getFormPayload(form).offer});});}
function initNotifyForm(){var form=document.getElementById('notify-form');var message=document.getElementById('notify-message');if(!form)return;form.addEventListener('submit',function(e){e.preventDefault();if(message){message.textContent='Request noted. Enrollment windows are announced on the store page — check back or contact us directly to confirm timing.';}
trackStoreEvent('store_notify_interest_submitted',{funnel_offer:getFormPayload(document.getElementById('purchase-intent-form')||form).offer||'',source:'offseason_waitlist'});form.reset();});}
function applyOfferFromQuery(form){var params=new URLSearchParams(window.location.search);var requested=String(params.get('offer')||'').trim();if(!requested)return;var offerSelect=document.getElementById('purchase-offer');if(!offerSelect)return;var match=Array.prototype.find.call(offerSelect.options,function(option){return option.value===requested;});if(!match)return;offerSelect.value=requested;updateOfferState(form);}
function selectOffer(form,offerCode){var offerSelect=document.getElementById('purchase-offer');if(!form||!offerSelect||!offerCode)return;offerSelect.value=offerCode;updateOfferState(form);var paidPath=document.getElementById('paid-path');if(paidPath){paidPath.scrollIntoView({behavior:'smooth',block:'start'});}}
function initOfferCartButtons(form){var feedback=document.getElementById('purchase-intent-message')||document.getElementById('store-cart-feedback');document.querySelectorAll('.store-cart-btn').forEach(function(button){button.addEventListener('click',function(){var offerCode=String(button.getAttribute('data-offer-code')||'').trim();var offerLabel=String(button.getAttribute('data-offer-label')||'').trim();var offerPrice=Number(button.getAttribute('data-offer-price')||0);if(window.EFI&&EFI.Auth&&typeof EFI.Auth.addToCart==='function'){EFI.Auth.addToCart({id:offerCode,name:offerLabel,price:offerPrice});}
selectOffer(form,offerCode);if(feedback){feedback.textContent=offerLabel+' added. The purchase form below is now set to that offer.';}
trackStoreEvent('store_offer_added_to_cart',{funnel_offer:offerCode});});});}
document.addEventListener('DOMContentLoaded',function(){var form=document.getElementById('purchase-intent-form');var checkoutBtn=document.getElementById('direct-checkout-btn');var offerSelect=document.getElementById('purchase-offer');if(!form)return;form.addEventListener('submit',function(e){e.preventDefault();submitPurchaseIntent(form);});if(offerSelect){offerSelect.addEventListener('change',function(){updateOfferState(form);});}
if(checkoutBtn){checkoutBtn.addEventListener('click',function(){startDirectCheckout(form);});}
var modal=document.getElementById('checkout-modal');var closeBtn=document.getElementById('checkout-modal-close');if(closeBtn){closeBtn.addEventListener('click',closeModal);}
document.addEventListener('keydown',function(e){if(e.key==='Escape'&&modal&&modal.style.display!=='none'){closeModal();}});initAbandonTracking(form);applyOfferFromQuery(form);updateOfferState(form);initNotifyForm();initOfferCartButtons(form);});})();